var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一個重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"一直盤踞在腦海中的她，是你在未來必須要面對的命運中，一個不可或缺的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你決定了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치자, 당신은 어느새 그녀의 앞에 서게 되었다.","JPN":"意を決すると、あなたのいつの間にか彼女の前に立っていた。","ENG":"As you steady yourself, you realize you're standing directly in her presence.","TWN":"做好心理準備後，不知不覺你便已經站在她的面前。"},"stage":{"bg":"BLACK","bgm":"THEMA_ECCLESIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MORS_SHADOW_CA_SPECIAL","text":{"KOREA":"너의 기도를 들었다. 나와 영원을 함께 하고 싶다니. 기특한 이야기로구나.","JPN":"そなたの祈りを聞いた。我と永遠を共にしたいなど。健気なものである。","ENG":"I heard your prayer. How admirable of you to want to reach eternal life with me.","TWN":"我聽見了你的祈禱。你竟然想和我永遠在一起，真是特別。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_ECCLESIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_SPECIAL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MORS_SHADOW_CA_SPECIAL","text":{"KOREA":"허나 마왕의 권속이 된다는 것은 축복이 아닌 저주나 다름없으니. 나는 널 사도로 삼을 생각이 없다.","JPN":"だが、魔王の眷属になるということは祝福ではなく呪いも同然。我はそなたを使徒にするつもりはない。","ENG":"But becoming a servant of a Demon Lord is a curse, not a blessing. I seek no intention of making you an Apostle.","TWN":"只是成為魔王的人，並非祝福，而是詛咒，所以我並沒有想收你為使徒。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_ECCLESIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_SPECIAL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MORS_SHADOW_CA_SPECIAL","text":{"KOREA":"그렇다 해도… 너의 간절함을 외면하는 것은 쉽지 않은 일이구나.","JPN":"だとしても……そなたの切実な願いから目を背けることは厳しいことであるな。","ENG":"Even so... I find it difficult to turn a blind eye on your desperation.","TWN":"話雖如此…但我很難不去在意你的懇求。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_ECCLESIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_SPECIAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MORS_SHADOW_CA_SPECIAL","text":{"KOREA":"이리 가까이 오거라.","JPN":"我に近寄れ｡","ENG":"Come closer.","TWN":"你過來，再靠近一點。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_ECCLESIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_SPECIAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MORS_SHADOW_CA_SPECIAL","text":{"KOREA":"그리 겁먹을 필요 없다. 아프지 않을 테니.","JPN":"そう恐れるでない。苦痛はないはずだ。","ENG":"There is no need to be afraid. It will not hurt.","TWN":"不需要害怕，不會痛的。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_ECCLESIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_SPECIAL","face":"UNIT_TOUCH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MORS_SHADOW_CA_SPECIAL","text":{"KOREA":"그리 겁먹을 필요 없다. 아프지 않을 테니.","JPN":"そう恐れるでない。苦痛はないはずだ。","ENG":"There is no need to be afraid. It will not hurt.","TWN":"不需要害怕，不會痛的。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_ECCLESIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_SPECIAL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_12"},{"id":"L15_1","type":"dialog","speaker":"MORS_SHADOW_CA_SPECIAL","text":{"KOREA":"이로서, 우리의 운명은 하나로 이어졌다.","JPN":"これより、我々の運命は一つとして繋がった。","ENG":"Now, our fates have become one. ","TWN":"如此，我們的命運已合而為一。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_ECCLESIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_SPECIAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MORS_SHADOW_CA_SPECIAL","text":{"KOREA":"네가 느끼는 기쁨은 나 또한 함께 누릴 것이고, 네가 겪게 될 아픔은 내가 함께 감내할지니.","JPN":"そなたの喜びはまた我の喜びとなり、そなたの痛みはまた我も共に背負うこととなる。","ENG":"All the joy and sorrow you feel, I will feel it as well.","TWN":"以後我們將一起同樂，也將一同受苦。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_ECCLESIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_SPECIAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MORS_SHADOW_CA_SPECIAL","text":{"KOREA":"이 지상의 그 무엇도 우리를 갈라놓을 수는 없으리라.","JPN":"もうこの地上に我々を引き離せるものは何もおらん。","ENG":"Nothing on this earth can separate us now.","TWN":"在這世上沒有任何人事物能使我們分開。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_ECCLESIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_SPECIAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MORS_SHADOW_CA_SPECIAL","text":{"KOREA":"네가 오롯이 날 숭배해왔듯, 나 또한 네 목소리만을 경청할 것이다.","JPN":"そなたが我だけを崇拝してきたように、我もまたそなたの声だけに耳を傾けるであろう。","ENG":"As you have worshipped me wholeheartedly, I shall only listen to your voice.","TWN":"就如同你一直以來只崇拜我一樣，我也會只傾聽你的聲音。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_ECCLESIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_SPECIAL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MORS_SHADOW_CA_SPECIAL","text":{"KOREA":"그래. 너는 내가 가진 것들 중 가장 특별하니까.","JPN":"そうだ。そなたは我の所有物でもっとも特別だからな。","ENG":"Yes. Since you are the most special among all that I own.","TWN":"沒錯，你是我所擁有的東西當中最特別的一個。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_ECCLESIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_SPECIAL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};